public class CircularLinkedList {
    public static class Node {
        int val;
        Node next;
        Node(int v) { val = v; }
    }

    // Storage: Head pointer
    private Node head = null;

    // Process & Storage: Insert at beginning
    public void insert(int val) {
        Node newNode = new Node(val); // Storage
        if (head == null) {
            head = newNode;
            newNode.next = head;
            return;
        }

        // Process: Find last node pointing to head
        Node temp = head; // Storage
        while (temp.next != head) {
            temp = temp.next;
        }
        temp.next = newNode;
        newNode.next = head;
        head = newNode; // Output
    }
}

