public class DoublyLinkedList {
    // Storage: DLL Node structure
    public static class DLLNode { 
        public int data;
        public DLLNode prev;
        public DLLNode next;

        public DLLNode(int data) {
            this.data = data;
        }
    }

    private DLLNode head = null;

    // Process & Storage: Insert at front
    public void insertFirst(int val) {
        DLLNode newNode = new DLLNode(val);
        if (head != null) {
            head.prev = newNode;
        }
        newNode.next = head;
        head = newNode;
    } 
}

public class MergeSortedCircularDLL {
    public static DoublyLinkedList.DLLNode merge(DoublyLinkedList.DLLNode head1, DoublyLinkedList.DLLNode head2) {
        // Input: two DLL heads
        if (head1 == null) return head2;
        if (head2 == null) return head1;

        // Process: break circular links temporarily to merge as linear
        DoublyLinkedList.DLLNode last1 = head1.prev; // Storage
        DoublyLinkedList.DLLNode last2 = head2.prev; // Storage
        last1.next = null; head1.prev = null;
        last2.next = null; head2.prev = null;

        DoublyLinkedList.DLLNode mergedHead = mergeLinear(head1, head2); // Storage

        // Process: find last node of merged list to restore circle
        DoublyLinkedList.DLLNode curr = mergedHead; // Storage
        while (curr.next != null) {
            curr = curr.next;
        }

        curr.next = mergedHead;
        mergedHead.prev = curr;

        // Output: return merged circular head
        return mergedHead;
    }

    private static DoublyLinkedList.DLLNode mergeLinear(DoublyLinkedList.DLLNode a, DoublyLinkedList.DLLNode b) {
        if (a == null) return b;
        if (b == null) return a;

        if (a.data <= b.data) {
            a.next = mergeLinear(a.next, b);
            a.next.prev = a;
            return a;
        } else {
            b.next = mergeLinear(a, b.next);
            b.next.prev = b;
            return b;
        }
    }
}

