public class DeleteAllKeyDLL {
    public static DoublyLinkedList.DLLNode deleteAll(DoublyLinkedList.DLLNode head, int x) {
        // Input: head and target value x
        if (head == null) return null;

        DoublyLinkedList.DLLNode current = head; // Storage

        // Process: traverse and delete nodes matching x
        while (current != null) {
            if (current.data == x) {
                DoublyLinkedList.DLLNode nextNode = current.next; // Storage

                // Handle head deletion
                if (current == head) {
                    head = current.next;
                    if (head != null) head.prev = null;
                } else {
                    // Adjust pointers to bypass current
                    if (current.prev != null) current.prev.next = current.next;
                    if (current.next != null) current.next.prev = current.prev;
                }
                current = nextNode;
            } else {
                current = current.next;
            }
        }
        // Output: return updated head reference
        return head;
    }
}

public class DeletePosDLL {
    public static DoublyLinkedList.DLLNode deleteAtPosition(DoublyLinkedList.DLLNode head, int position) {
        // Input: head pointer and index position
        if (head == null || position < 1) return head;

        DoublyLinkedList.DLLNode current = head; // Storage

        // Process: traverse to target position
        for (int i = 1; current != null && i < position; i++) {
            current = current.next;
        }

        if (current == null) return head; // Position out of bounds

        // Process: handles head deletion
        if (current == head) {
            head = current.next;
            if (head != null) head.prev = null;
            return head; // Output
        }

        // Process: bypass current node in list
        if (current.next != null) {
            current.next.prev = current.prev;
        }
        if (current.prev != null) {
            current.prev.next = current.next;
        }

        // Output: return updated head
        return head;
    }
}
